MANDATORY_A_SHARE_SUPPLEMENTS = (
    "600522.SH",
)

def unique_targets(codes):
    "Return codes in first-seen order with empty values removed."
    seen = set()
    result = []
    for code in codes:
        normalized = str(code or "").strip().upper()
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        result.append(normalized)
    return result

def a_share_supplement_targets():
    return unique_targets(CSI2000_MISSING_20260430 + MANDATORY_A_SHARE_SUPPLEMENTS)

def merge_a_share_targets(base_targets):
    return unique_targets(list(base_targets) + a_share_supplement_targets())
